(1, 'Taj Palace, New Delhi', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Delhi NCR', NULL, 'A landmark hotel in the heart of the diplomatic enclave, known for its grandeur and impeccable service.', 'https://www.tajhotels.com/en-in/taj/taj-palace-new-delhi/', '/hotel-images/taj-palace-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(2, 'The Taj Mahal Hotel, New Delhi', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Delhi NCR', NULL, 'An iconic landmark in Lutyens\' Delhi, offering a blend of timeless elegance and modern luxury.', 'https://www.tajhotels.com/en-in/taj/the-taj-mahal-hotel-new-delhi/', '/hotel-images/taj-mahal-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(3, 'Vivanta New Delhi, Dwarka', 'Indian Hotels Company Ltd. (IHCL)', 'Vivanta', 'Delhi NCR', NULL, 'A contemporary hotel located in the business district of Dwarka, with easy access to the airport.', 'https://www.vivantahotels.com/en-in/vivanta-new-delhi-dwarka/', '/hotel-images/vivanta-dwarka-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(4, 'ITC Maurya, a Luxury Collection Hotel, New Delhi', 'ITC Hotels', 'ITC Hotels', 'Delhi NCR', NULL, 'A premier luxury hotel in the heart of Delhi, known for its exceptional hospitality and culinary experiences.', 'https://www.itchotels.com/in/en/itcmaurya-newdelhi', '/hotel-images/itc-maurya-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(5, 'ITC Grand Bharat, a Luxury Collection Retreat, Gurgaon', 'ITC Hotels', 'ITC Hotels', 'Delhi NCR', NULL, 'A one-of-a-kind destination luxury resort, sprawling over 1.2 square kilometers, offering an unparalleled experience of Indian grandeur.', 'https://www.itchotels.com/in/en/itcgrandbharat-gurgaon', '/hotel-images/itc-grand-bharat-gurgaon.png', '2025-06-30 09:59:58', 'India'),
(6, 'The Oberoi, New Delhi', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Delhi NCR', NULL, 'A landmark hotel offering breathtaking views of the Delhi Golf Course and Humayun\'s Tomb, known for its contemporary design and warm hospitality.', 'https://www.oberoihotels.com/hotels-in-delhi/', '/hotel-images/the-oberoi-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(7, 'The Oberoi, Gurgaon', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Delhi NCR', NULL, 'A luxury hotel in the heart of Gurgaon, characterized by its striking architecture and serene ambiance.', 'https://www.oberoihotels.com/hotels-in-gurgaon/', '/hotel-images/the-oberoi-gurgaon.jpg', '2025-06-30 09:59:58', 'India'),
(8, 'The Leela Palace New Delhi', 'The Leela Palaces, Hotels and Resorts', 'The Leela', 'Delhi NCR', NULL, 'A modern palace hotel that epitomizes the grace and elegance of Lutyens\' Delhi.', 'https://www.theleela.com/the-leela-palace-new-delhi', '/hotel-images/the-leela-palace-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(9, 'The Leela Ambience Convention Hotel, Delhi', 'The Leela Palaces, Hotels and Resorts', 'The Leela', 'Delhi NCR', NULL, 'A strategically located hotel with one of the largest meeting and banqueting spaces in India.', 'https://www.theleela.com/the-leela-ambience-convention-hotel-delhi', '/hotel-images/the-leela-ambience-convention-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(10, 'Roseate House New Delhi', 'Roseate Hotels & Resorts', 'Roseate', 'Delhi NCR', NULL, 'A contemporary upscale hotel located in the Aerocity hospitality district, known for its unique design and hospitality.', 'https://www.roseatehotels.com/newdelhi/roseatehouse/', '/hotel-images/roseate-house-aerocity-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(11, 'The Roseate New Delhi', 'Roseate Hotels & Resorts', 'Roseate', 'Delhi NCR', NULL, 'An urban oasis with lush green landscapes and serene water bodies, offering a tranquil escape.', 'https://www.roseatehotels.com/newdelhi/theroseate/', '/hotel-images/roseate-house-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(12, 'Jaypee Vasant Continental', 'Jaypee Hotels & Resorts', 'Jaypee', 'Delhi NCR', NULL, 'A 5-star hotel located in the Vasant Vihar area, known for its warm hospitality and excellent dining options.', 'https://www.jaypeehotels.com/delhi/vasant-continental', '/hotel-images/jaypee_vasant_continental-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(13, 'Jaypee Siddharth', 'Jaypee Hotels & Resorts', 'Jaypee', 'Delhi NCR', NULL, 'A 5-star hotel in the heart of Delhi, offering a blend of business and pleasure.', 'https://www.jaypeehotels.com/delhi/siddharth', '/hotel-images/jaypee-siddharth-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(14, 'The Claridges New Delhi', 'The Claridges Hotels & Resorts', 'The Claridges', 'Delhi NCR', NULL, 'A historic hotel in Lutyens\' Delhi, known for its old-world charm and personalized service.', 'https://www.claridges.com/', '/hotel-images/the-claridges-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(15, 'The Imperial New Delhi', 'The Imperial New Delhi', 'The Imperial', 'Delhi NCR', NULL, 'A historic luxury hotel, known for its colonial elegance and priceless art collection.', 'https://theimperialindia.com/', '/hotel-images/The-Imperial-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(17, 'Andaz Delhi', 'Hyatt Hotels Corporation', 'Andaz', 'New Delhi', NULL, 'A luxury lifestyle hotel in Aerocity, offering a unique and vibrant experience that is rooted in the local culture of Delhi.', 'https://www.hyatt.com/en-US/hotel/india/andaz-delhi/delaz', '/hotel-images/andaz-aerocity-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(18, 'JW Marriott Hotel New Delhi Aerocity', 'Marriott International', 'JW Marriott', 'New Delhi', NULL, 'A luxury hotel located in the Aerocity, offering a seamless blend of comfort and convenience.', 'https://www.marriott.com/en-us/hotels/delap-jw-marriott-hotel-new-delhi-aerocity/overview/', '/hotel-images/jw-marriott-aerocity-new-delhi.jpg', '2025-06-30 09:59:58', 'India'),
(19, 'Rambagh Palace, Jaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Jaipur', NULL, 'Often called the \'Jewel of Jaipur\', this former royal residence offers a glimpse into the opulent lifestyle of the Maharajas.', 'https://www.tajhotels.com/en-in/taj/rambagh-palace-jaipur/', '/hotel-images/taj-rambagh-palace-jaipur.jpg', '2025-06-30 09:59:58', 'India'),
(20, 'Jai Mahal Palace, Jaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Jaipur', NULL, 'A stunning piece of Rajasthan\'s heritage, this 270-year-old palace is set amidst 18 acres of landscaped Mughal gardens.', 'https://www.tajhotels.com/en-in/taj/jai-mahal-palace-jaipur/', '/hotel-images/taj-jai-mahal-palace-jaipur.avif', '2025-06-30 09:59:58', 'India'),
(21, 'Vivanta Jaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Vivanta', 'Jaipur', NULL, 'A contemporary hotel offering a blend of modern design and traditional Rajasthani hospitality.', 'https://www.vivantahotels.com/en-in/vivanta-jaipur/', 'https://cdn.sanity.io/images/ocl5w36p/prod5/656370531974b1e1cd59b831ca9891c88fa2968a-3840x1860.jpg', '2025-06-30 09:59:58', 'India'),
(22, 'ITC Rajputana, a Luxury Collection Hotel, Jaipur', 'ITC Hotels', 'ITC Hotels', 'Jaipur', NULL, 'Inspired by the havelis of Rajasthan, this hotel offers a blend of traditional architecture and modern amenities.', 'https://www.itchotels.com/in/en/itcrajputana-jaipur', '/hotel-images/itc-rajputana-jaipur.jpg', '2025-06-30 09:59:58', 'India'),
(23, 'The Oberoi Rajvilas, Jaipur', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Jaipur', NULL, 'A luxurious resort set in 32 acres of landscaped gardens with pavilions and reflection pools, offering an oasis of tranquility.', 'https://www.oberoihotels.com/hotels-in-jaipur-rajvilas-resort/', '/hotel-images/the-oberoi-rajvilas-jaipur.jpg', '2025-06-30 09:59:58', 'India'),
(24, 'Hilton Jaipur', 'Hilton Hotels & Resorts', 'Hilton', 'Jaipur', NULL, 'Located in the heart of the city, this hotel offers a blend of contemporary style and Rajasthani hospitality.', 'https://www.hilton.com/en/hotels/jaihihi-hilton-jaipur/', '/hotel-images/hilton-jaipur.avif', '2025-06-30 09:59:58', 'India'),
(25, 'Taj Lake Palace, Udaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Udaipur', NULL, 'An iconic floating palace on Lake Pichola, offering breathtaking views and a truly magical experience.', 'https://www.tajhotels.com/en-in/taj/taj-lake-palace-udaipur/', '/hotel-images/taj-lake-palace-udaipur.jpg', '2025-06-30 09:59:58', 'India'),
(26, 'Taj Fateh Prakash Palace, Udaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Udaipur', NULL, 'A heritage hotel within the City Palace Complex, offering panoramic views of Lake Pichola.', 'https://www.tajhotels.com/en-in/taj/taj-fateh-prakash-palace-udaipur/', '/hotel-images/taj-fateh-prakash-palace-udaipur.avif', '2025-06-30 09:59:58', 'India'),
(27, 'Vivanta Udaipur', 'Indian Hotels Company Ltd. (IHCL)', 'Vivanta', 'Udaipur', NULL, 'A contemporary hotel with stunning views of the Aravalli Hills and the city\'s lakes.', 'https://www.vivantahotels.com/en-in/vivanta-udaipur/', 'https://cdn.sanity.io/images/ocl5w36p/prod5/656370531974b1e1cd59b831ca9891c88fa2968a-3840x1860.jpg', '2025-06-30 09:59:58', 'India'),
(28, 'The Oberoi Udaivilas, Udaipur', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Udaipur', NULL, 'A spectacular luxury resort on the banks of Lake Pichola, showcasing the rich heritage of the Mewar region of Rajasthan.', 'https://www.oberoihotels.com/hotels-in-udaipur-udaivilas-resort/', '/hotel-images/the-oberoi-udaivilas-udaipur.avif', '2025-06-30 09:59:58', 'India'),
(29, 'The Leela Palace Udaipur', 'The Leela Palaces, Hotels and Resorts', 'The Leela', 'Udaipur', NULL, 'A modern palace hotel on the banks of Lake Pichola, offering breathtaking views of the lake and the Aravalli mountains.', 'https://www.theleela.com/the-leela-palace-udaipur', '/hotel-images/the-leela-palace-udaipur.jpg', '2025-06-30 09:59:58', 'India'),
(30, 'ITC Mughal, a Luxury Collection Hotel, Agra', 'ITC Hotels', 'ITC Hotels', 'Agra', NULL, 'A tribute to the great Mughal builders, this hotel is a splendid display of Mughal architecture and landscaped gardens.', 'https://www.itchotels.com/in/en/itcmughal-agra', '/hotel-images/itc-mughal-agra.jpg', '2025-06-30 09:59:58', 'India'),
(31, 'The Oberoi Amarvilas, Agra', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Agra', NULL, 'Located just 600 meters from the Taj Mahal, this luxury hotel offers uninterrupted views of the iconic monument from every room.', 'https://www.oberoihotels.com/hotels-in-agra-amarvilas-resort/', '/hotel-images/the-oberoi-amarvilas-agra.webp', '2025-06-30 09:59:58', 'India'),
(32, 'Jaypee Palace Hotel & Convention Centre, Agra', 'Jaypee Hotels & Resorts', 'Jaypee', 'Agra', NULL, 'A landmark hotel in Agra, built of red sandstone and marble, it is a blend of Mughal and contemporary architecture.', 'https://www.jaypeehotels.com/agra/jaypee-palace', '/hotel-images/jaypee-palace-agra.jpg', '2025-06-30 09:59:58', 'India'),
(33, 'The Taj Mahal Palace, Mumbai', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Mumbai', NULL, 'An iconic landmark overlooking the Gateway of India, offering a blend of history, luxury, and warm hospitality.', 'https://www.tajhotels.com/en-in/taj/the-taj-mahal-palace-mumbai/', '/hotel-images/taj-mahal-palace-mumbai.jpg', '2025-06-30 09:59:58', 'India'),
(34, 'Taj Lands End, Mumbai', 'Indian Hotels Company Ltd. (IHCL)', 'Taj', 'Mumbai', NULL, 'A luxury hotel in the heart of Bandra, offering stunning views of the Arabian Sea and the Bandra-Worli Sea Link.', 'https://www.tajhotels.com/en-in/taj/taj-lands-end-mumbai/', '/hotel-images/taj-land-end-mumbai.jpg', '2025-06-30 09:59:58', 'India'),
(35, 'The Oberoi, Mumbai', 'The Oberoi Group', 'Oberoi Hotels & Resorts', 'Mumbai', NULL, 'A contemporary luxury hotel located on Marine Drive, offering stunning views of the ocean and the city\'s skyline.', 'https://www.oberoihotels.com/hotels-in-mumbai/', '/hotel-images/the-oberoi-mumbai.jpg', '2025-06-30 09:59:58', 'India'),
