(606, 'Burj Al Arab', 'Jumeirah', 'Jumeirah', 'Dubai', '', 'Step beyond our doors into an oasis of profound tranquility. We have masterfully blended timeless elegance with the finest contemporary luxury, creating a sanctuary where classic architectural grace coexists with state-of-the-art comforts for a truly memorable escape.', 'https://www.jumeirah.com/en/stay/dubai/burj-al-arab-jumeirah', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(607, 'Atlantis The Palm', 'Atlantis', 'Kerzner International Holdings', 'Dubai', '', 'We invite you to experience a world of refined sophistication, where every detail is meticulously curated to delight the senses. From the art on the walls to the texture of the linens, your entire stay is designed to be an immersive journey into unparalleled comfort and style.', 'https://www.atlantis.com/atlantis-the-palm', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(608, 'Jumeirah Al Naseem', 'Jumeirah', 'Jumeirah', 'Dubai', '', 'Conceived as an exclusive sanctuary for the discerning global traveler, our hotel offers a private and sophisticated retreat from the world outside. Here, privacy, elegance, and personalized attention combine to create an environment of serene, understated luxury.', 'https://www.jumeirah.com/en/stay/dubai/jumeirah-al-naseem', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(609, 'Address Downtown', 'Address', 'Emaar Hospitality Group', 'Dubai', '', 'We believe that true luxury lies in the moments that take your breath away. Our purpose is to craft a seamless narrative for your stay, where every experience, from a private dinner to a quiet morning coffee, is thoughtfully designed to become an unforgettable memory.', 'https://www.addresshotels.com/en/hotels/address-downtown/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(610, 'JW Marriott Marquis Hotel Dubai', 'JW Marriott', 'Marriott International', 'Dubai', '', 'Your stay is a carefully composed symphony of sophisticated design and warm, intuitive hospitality. The stunning visual aesthetics of our spaces are perfectly matched by a service culture that anticipates your needs, ensuring a stay that is as flawless as it is beautiful.', 'https://www.marriott.com/en-us/hotels/dxbjw-jw-marriott-marquis-hotel-dubai/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(611, 'The St. Regis Dubai, The Palm', 'St. Regis', 'Marriott International', 'Dubai', '', 'Discover a true haven of serenity nestled in the heart of the vibrant city. Our property is a destination in itself, offering a peaceful respite where you can unwind in an atmosphere of bespoke luxury and escape the ordinary in every possible way.', 'https://www.marriott.com/en-us/hotels/dxbpx-the-st-regis-dubai-the-palm/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(612, 'The Ritz-Carlton, Dubai', 'The Ritz-Carlton', 'Marriott International', 'Dubai', '', 'Welcome to the pinnacle of opulence, an establishment dedicated to providing a truly transcendent guest experience. We go beyond mere accommodation to offer a lifestyle of glamour, comfort, and exclusivity that will redefine your expectations of what a hotel can be.', 'https://www.ritzcarlton.com/en/hotels/dxbrz-the-ritz-carlton-dubai/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(613, 'Four Seasons Resort Dubai at Jumeirah Beach', 'Four Seasons', 'Four Seasons Hotels and Resorts', 'Dubai', '', 'From the moment you arrive, you will step into a realm of exceptional style and uncompromising quality. Every element of our hotel has been chosen with intent, reflecting a commitment to superior craftsmanship, aesthetic integrity, and the highest standards of guest comfort.', 'https://www.fourseasons.com/dubaijb/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(614, 'Mandarin Oriental Jumeira, Dubai', 'Mandarin Oriental', 'Mandarin Oriental Hotel Group', 'Dubai', '', 'We don\'t just offer a place to stay; we curate a comprehensive and immersive experience tailored to your desires. Our goal is for you to depart with a unique story to tell, filled with moments of discovery, relaxation, and unparalleled personal service.', 'https://www.mandarinoriental.com/en/dubai/jumeira', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(615, 'One&Only Royal Mirage', 'One&Only', 'Kerzner International Holdings', 'Dubai', '', 'As a landmark of distinguished hospitality, our hotel is an icon of architectural grace and refined living. We honor our legacy by continuing a tradition of excellence, offering a timeless escape for those who appreciate history, elegance, and world-class service.', 'https://www.oneandonlyresorts.com/royal-mirage', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(616, 'Raffles The Palm', 'Raffles', 'Accor', 'Dubai', '', 'Experience hospitality gracefully redefined, where our service philosophy is built on quiet anticipation. Our team is expertly trained to foresee your needs and fulfill them with a seamless elegance that ensures your stay is utterly effortless and perfectly choreographed.', 'https://www.rafflesthepalmdubai.com/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(617, 'Shangri-La Dubai', 'Shangri-La', 'Shangri-La Hotels and Resorts', 'Dubai', '', 'Our unwavering commitment to excellence is evident in every personalized touch and thoughtful gesture. From a welcome that feels like a homecoming to a departure that feels like a farewell to friends, we infuse every interaction with genuine care and meticulous attention.', 'https://www.shangri-la.com/en/dubai/shangrila/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(618, 'Anantara The Palm Dubai Resort', 'Anantara', 'Minor Hotels', 'Dubai', '', 'Discover a place where intuitive service and meticulous attention to detail are our most profound hallmarks. Our staff operates with a discreet yet present grace, ensuring your environment is always perfect and your requests are met before you even have to ask.', 'https://www.anantara.com/en/palm-dubai', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(619, 'Waldorf Astoria Dubai Palm Jumeirah', 'Waldorf Astoria', 'Hilton', 'Dubai', '', 'We are custodians of a legacy of service, dedicated to making your stay both seamless and extraordinary. This long-standing tradition of hospitality excellence is the foundation upon which we build every modern, luxurious experience for our guests.', 'https://www.hilton.com/en/hotels/dxbpdwa-waldorf-astoria-dubai-palm-jumeirah/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(620, 'Bvlgari Resort Dubai', 'Bulgari', 'Marriott International', 'Dubai', '', 'Here, you will discover the art of hospitality, perfected for the modern connoisseur. We blend time-honored traditions of service with innovative solutions to create a guest experience that is both classic in its quality and contemporary in its execution.', 'https://www.bulgarihotels.com/en_US/dubai/the-resort/overview', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(621, 'Jumeirah Beach Hotel', 'Jumeirah', 'Jumeirah', 'Dubai', '', 'Our dedicated team is the heart of your experience, devoted to providing a flawless and deeply personalized stay. Consider our concierge and guest relations staff your personal curators, ready to unlock the very best of what our destination has to offer.', 'https://www.jumeirah.com/en/stay/dubai/jumeirah-beach-hotel', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(622, 'Fairmont The Palm', 'Fairmont', 'Accor', 'Dubai', '', 'True luxury is found in anticipatory service that effortlessly turns fleeting moments into cherished memories. Whether it’s remembering your preferred newspaper or arranging a last-minute reservation, our passion is to make your stay uniquely and wonderfully yours.', 'https://www.fairmont.com/en/hotels/dubai/fairmont-the-palm.html', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(623, 'Sofitel Dubai The Palm Resort & Spa', 'Sofitel', 'Accor', 'Dubai', '', 'Experience our signature discreet and intuitive service, meticulously tailored to your personal preferences and rhythms. We pride ourselves on creating a bubble of comfort around you, where everything you need seems to appear exactly when you desire it.', 'https://www.sofitel-dubai-thepalm.com/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(624, 'Palazzo Versace Dubai', 'Palazzo Versace Dubai', 'Independent / Co-Branded', 'Dubai', '', 'We have cultivated a warm and welcoming environment of effortless luxury, where sophistication never feels cold or impersonal. Our team prides itself on creating genuine connections, making our grand hotel feel like your own private, elegant home.', 'https://www.palazzoversace.ae/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(625, 'Grand Hyatt Dubai', 'Grand Hyatt', 'Hyatt Hotels', 'Dubai', '', 'From your first moment of arrival to your final departure, you will be enveloped in a standard of service that is both technically impeccable and genuinely warm. We strive for a perfect balance of professional precision and heartfelt hospitality.', 'https://www.hyatt.com/en-US/hotel/united-arab-emirates/grand-hyatt-dubai/dubai', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(626, 'Rixos The Palm Hotel & Suites', 'Rixos', 'Accor', 'Dubai', '', 'Our hotel is a living masterpiece of architectural grace and curated interior design. Every corridor, lounge, and guest room is a gallery of bespoke furniture, commissioned art, and thoughtful details, creating an atmosphere of immersive beauty.', 'https://www.rixos.com/en/hotel-resort/rixos-palm-hotel-suites', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(627, 'The Lana - Dorchester Collection', 'Dorchester', 'Dorchester Collection', 'Dubai', '', 'Retreat to your private haven of sumptuous comfort and serene, residential style. Our accommodations are designed to be more than just a room; they are tranquil sanctuaries where you can relax, recharge, and feel completely at ease.', 'https://www.dorchestercollection.com/en/dubai/the-lana', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(628, 'Le Meridien Dubai Hotel & Conference Centre', 'Le Meridien', 'Marriott International', 'Dubai', '', 'Each of our rooms and suites is a thoughtfully appointed sanctuary of comfort, space, and elegance. Outfitted with plush textiles, cutting-edge technology, and spa-like bathrooms, they provide the ultimate environment for rest and rejuvenation.', 'https://www.marriott.com/en-us/hotels/dxbmd-le-meridien-dubai-hotel-and-conference-centre/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(629, 'Taj Dubai', 'Taj', 'Indian Hotels Company Ltd. (IHCL)', 'Dubai', '', 'We are an iconic destination where classic sophistication and modern allure converge in a breathtaking display. Our design narrative respects timeless aesthetics while embracing contemporary innovation, resulting in a property that is both grand and relevant.', 'https://www.tajhotels.com/en-in/taj/taj-dubai/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(630, 'W Dubai - The Palm', 'W Hotels', 'Marriott International', 'Dubai', '', 'Discover accommodations that are both a destination in themselves and a deeply personal retreat. The thoughtful layout, luxurious amenities, and serene ambiance of our rooms ensure that your time spent inside is just as memorable as your time spent exploring.', 'https://www.marriott.com/en-us/hotels/dxbwh-w-dubai-the-palm/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(631, 'SLS Dubai', 'SLS', 'Accor', 'Dubai', '', 'We invite you to unwind in meticulously designed spaces that blend opulent materials with the comforts of a private residence. The result is an atmosphere of elevated living that feels both aspirational and intimately familiar, perfect for short or extended stays.', 'https://slshotels.com/dubai/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(632, 'The Canvas Dubai - MGallery Hotel Collection', 'MGallery', 'Accor', 'Dubai', '', 'An environment of bespoke luxury and artisanal craftsmanship awaits you at every turn. From hand-stitched leather accents to custom-forged metalwork, our commitment to quality is tangible, offering a feast for the eyes and a testament to fine design.', 'https://all.accor.com/hotel/7008/index.en.shtml', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(633, 'The Ritz-Carlton, Dubai International Financial Centre', 'The Ritz-Carlton', 'Marriott International', 'Dubai', '', 'Indulge in unparalleled comfort with our signature plush furnishings, intuitive state-of-the-art amenities, and serene soundproofing. Every room is an enclave designed for deep relaxation and a perfect night\'s sleep, ensuring you wake up refreshed and inspired.', 'https://www.ritzcarlton.com/en/hotels/dxbrz-the-ritz-carlton-dubai-international-financial-centre/overview/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(634, 'Jumeirah Al Qasr Dubai', 'Jumeirah', 'Jumeirah', 'Dubai', '', 'Within our walls, aesthetic beauty and ultimate comfort exist in perfect, harmonious balance. The visual delight of our interiors is matched only by the physical comfort of our accommodations, ensuring a stay that satisfies both the eye and the soul.', 'https://www.jumeirah.com/en/stay/dubai/jumeirah-al-qasr', '', '2025-08-29 15:20:37', 'United Arab Emirates');
INSERT INTO `hotels` (`id`, `hotel_name`, `parent_company`, `sub_brand`, `city`, `state`, `description`, `website_url`, `hero_image_url`, `created_at`, `country`) VALUES
(635, 'Bab Al Shams Desert Resort', 'Bab Al Shams', 'Kerzner International Holdings', 'Dubai', '', 'For those seeking the pinnacle of refinement, our suites offer an elevated experience of space, privacy, and exquisite detail. Featuring separate living areas, expansive views, and exclusive amenities, they represent the ultimate expression of our luxurious hospitality.', 'https://www.babalshams.com/', '', '2025-08-29 15:20:37', 'United Arab Emirates'),
(636, 'Shangri-La Kuala Lumpur', 'Shangri-La', 'Shangri-La Hotels and Resorts', 'Kuala Lumpur', '', 'Prepare to embark on an epicurean journey that tantalizes the senses and expands the palate. Our dining venues are celebrated destinations, each offering a unique culinary story told through innovative menus and the freshest seasonal ingredients.', 'https://www.shangri-la.com/kualalumpur/shangrila/', '', '2025-08-29 15:20:37', 'Malaysia'),
(637, 'The Ritz-Carlton, Kuala Lumpur', 'The Ritz-Carlton', 'YTL Corporation Berhad', 'Kuala Lumpur', '', 'We invite you to savor gastronomic excellence at our world-class dining destinations. Helmed by acclaimed chefs, our restaurants are temples of culinary creativity, where every dish is a work of art and every meal is an unforgettable event.', 'https://www.ritzcarlton.com/en/hotels/kulrz-the-ritz-carlton-kuala-lumpur/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(638, 'Four Seasons Hotel Kuala Lumpur', 'Four Seasons', 'Four Seasons Hotels and Resorts', 'Kuala Lumpur', '', 'Rejuvenate your mind, body, and soul in our tranquil and exclusive wellness sanctuary. Offering a curated menu of restorative treatments, cutting-edge fitness equipment, and serene relaxation areas, it is a space wholly dedicated to your personal wellbeing.', 'https://www.fourseasons.com/kualalumpur/', '', '2025-08-29 15:20:37', 'Malaysia'),
(639, 'Mandarin Oriental, Kuala Lumpur', 'Mandarin Oriental', 'Mandarin Oriental Hotel Group', 'Kuala Lumpur', '', 'Our hotel is a celebrated destination for both culinary artistry and masterful mixology. Gather in our stylish bar for a handcrafted cocktail before transitioning to a dinner that showcases global flavors and exquisite culinary technique.', 'https://www.mandarinoriental.com/en/kuala-lumpur/petronas-towers/', '', '2025-08-29 15:20:37', 'Malaysia'),
(640, 'Grand Hyatt Kuala Lumpur', 'Grand Hyatt', 'Hyatt Hotels', 'Kuala Lumpur', '', 'Escape to a state of blissful relaxation with our bespoke spa treatments and holistic wellness programs. Our expert therapists use world-class products and personalized techniques to melt away stress, leaving you feeling balanced, restored, and radiant.', 'https://www.hyatt.com/en-US/hotel/malaysia/grand-hyatt-kuala-lumpur/kuagh', '', '2025-08-29 15:20:37', 'Malaysia'),
(641, 'JW Marriott Kuala Lumpur', 'JW Marriott', 'Marriott International', 'Kuala Lumpur', '', 'Indulge in vibrant and authentic culinary creations crafted from the finest locally-sourced and seasonal ingredients. Our food philosophy is rooted in a passion for quality and sustainability, bringing you a true taste of the region\'s best offerings.', 'https://www.marriott.com/en-us/hotels/kuldt-jw-marriott-hotel-kuala-lumpur/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(642, 'The St. Regis Kuala Lumpur', 'St. Regis', 'Marriott International', 'Kuala Lumpur', '', 'Discover a holistic approach to wellbeing that extends beyond our spa to encompass every aspect of your stay. From nourishing menu options to in-room wellness amenities, we provide the tools to help you maintain balance and vitality while you travel.', 'https://www.marriott.com/en-us/hotels/kulxr-the-st-regis-kuala-lumpur/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(643, 'EQ Kuala Lumpur', 'EQ', 'EQ Hospitality Sdn Bhd', 'Kuala Lumpur', '', 'From the casual elegance of our all-day bistro to the refined ambiance of our signature fine dining room, a taste of perfection awaits. We offer a diverse array of culinary settings, each defined by its exceptional quality and impeccable service.', 'https://www.eqkualalumpur.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(644, 'Le Méridien Kuala Lumpur', 'Le Meridien', 'Marriott International', 'Kuala Lumpur', '', 'Your personal journey to tranquility and rejuvenation begins the moment you enter our wellness space. It is a quiet, restorative world designed to soothe the senses, calm the mind, and provide a peaceful escape from the demands of daily life.', 'https://www.marriott.com/en-us/hotels/kulmd-le-meridien-kuala-lumpur/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(645, 'The RuMa Hotel and Residences', 'The RuMa', 'Urban Resorts Concepts', 'Kuala Lumpur', '', 'Join us for a celebration of flavor, artistry, and exceptional service in our acclaimed restaurants. We create dining experiences that are both sophisticated and deeply satisfying, making every meal a special and memorable occasion.', 'https://www.theruma.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(646, 'PARKROYAL COLLECTION Kuala Lumpur', 'PARKROYAL COLLECTION', 'Pan Pacific Hotels Group', 'Kuala Lumpur', '', 'We offer more than just amenities; we provide the definitive experience of modern luxury. This is a place where sophisticated design, intuitive technology, and a forward-thinking approach to hospitality converge to create an environment that is as inspiring as it is comfortable.', 'https://www.panpacific.com/en/hotels-and-resorts/pr-collection-kuala-lumpur.html', '', '2025-08-29 15:20:37', 'Malaysia'),
(647, 'W Kuala Lumpur', 'W Hotels', 'Marriott International', 'Kuala Lumpur', '', 'To stay with us is to inhabit an address of distinction and international prestige. Our iconic property is more than a hotel—it is a landmark of culture and sophistication, offering an exclusive and elegant base from which to experience the world.', 'https://www.marriott.com/en-us/hotels/kulwh-w-kuala-lumpur/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(648, 'The Majestic Hotel Kuala Lumpur', 'The Majestic', 'YTL Hotels', 'Kuala Lumpur', '', 'We have built our reputation on the belief that extraordinary experiences should be the standard, not the exception. Every aspect of our operation, from our grand public spaces to the smallest in-room detail, is engineered to exceed expectations and deliver delight.', 'https://www.majestichotelkl.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(649, 'Shangri-La Rasa Ria, Kota Kinabalu', 'Shangri-La', 'Shangri-La Hotels and Resorts', 'Kota Kinabalu', '', 'Consider us your private and luxurious escape from the everyday. We provide a protected, elegant environment where the pressures of the world fade away, allowing you the time and space to reconnect with yourself and savor the quiet moments of peace and comfort.', 'https://www.shangri-la.com/kotakinabalu/rasariaresort/', '', '2025-08-29 15:20:37', 'Malaysia'),
(650, 'Hyatt Regency Kinabalu', 'Hyatt Regency', 'Hyatt Hotels', 'Kota Kinabalu', '', 'Welcome to the ultimate expression of refined living, where every detail has been considered for a life lived beautifully. Our hotel is for those who appreciate the finer things—art, design, gastronomy, and service—all delivered with an effortless, confident grace.', 'https://www.hyatt.com/en-US/hotel/malaysia/hyatt-regency-kinabalu/bkihr', '', '2025-08-29 15:20:37', 'Malaysia'),
(651, 'The Pacific Sutera Hotel', 'The Pacific', 'Sutera Harbour Resort', 'Kota Kinabalu', '', 'Our experience has been meticulously curated for those who expect the very best and appreciate a discerning eye for quality. We are not for everyone; we are for the traveler who seeks a unique, character-rich environment that stands apart from the ordinary.', 'https://www.suteraharbour.com/the-pacific-sutera-hotel', '', '2025-08-29 15:20:37', 'Malaysia'),
(652, 'Four Seasons Resort Langkawi', 'Four Seasons', 'Four Seasons Hotels and Resorts', 'Langkawi', '', 'Here, timeless elegance and unforgettable moments are woven into the very fabric of the guest experience. We offer a classic, enduring style of luxury, focusing on creating genuine, heartfelt memories that you will cherish long after you have departed.', 'https://www.fourseasons.com/langkawi/', '', '2025-08-29 15:20:37', 'Malaysia'),
(653, 'The Datai Langkawi', 'The Datai', 'The Datai Hotels', 'Langkawi', '', 'We are proud to set a new standard in bespoke hospitality, moving beyond a one-size-fits-all approach to luxury. We listen, we learn, and we adapt, creating a highly personalized and fluid experience that is built entirely around you, the individual guest.', 'https://www.thedatai.com/langkawi/', '', '2025-08-29 15:20:37', 'Malaysia'),
(654, 'The Ritz-Carlton, Langkawi', 'The Ritz-Carlton', 'Marriott International', 'Langkawi', '', 'Discover the art of luxury, perfectly expressed in every facet of our hotel. It is an art form that we have perfected over years, balancing grandeur with intimacy, and tradition with innovation, to create a masterpiece of modern hospitality.', 'https://www.ritzcarlton.com/en/hotels/lgkrz-the-ritz-carlton-langkawi/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(655, 'The St. Regis Langkawi', 'St. Regis', 'Marriott International', 'Langkawi', '', 'Welcome to a world beyond compare, where the boundaries of service and luxury are constantly being reimagined. Your stay with us is an invitation to experience the extraordinary and to see just how magnificent and memorable travel can truly be.', 'https://www.marriott.com/en-us/hotels/lgkxr-the-st-regis-langkawi/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(656, 'The Westin Langkawi Resort & Spa', 'The Westin', 'Marriott International', 'Langkawi', '', 'Step beyond our doors into an oasis of profound tranquility. We have masterfully blended timeless elegance with the finest contemporary luxury, creating a sanctuary where classic architectural grace coexists with state-of-the-art comforts for a truly memorable escape.', 'https://www.marriott.com/en-us/hotels/lgkwl-the-westin-langkawi-resort-and-spa/overview/', '', '2025-08-29 15:20:37', 'Malaysia'),
(657, 'Berjaya Langkawi Resort', 'Berjaya', 'Berjaya Corporation Berhad', 'Langkawi', '', 'We invite you to experience a world of refined sophistication, where every detail is meticulously curated to delight the senses. From the art on the walls to the texture of the linens, your entire stay is designed to be an immersive journey into unparalleled comfort and style.', 'https://www.berjayahotels.com/langkawi/', '', '2025-08-29 15:20:37', 'Malaysia'),
(658, 'Pangkor Laut Resort', 'Pangkor Laut', 'YTL Hotels', 'Pangkor Island', '', 'Conceived as an exclusive sanctuary for the discerning global traveler, our hotel offers a private and sophisticated retreat from the world outside. Here, privacy, elegance, and personalized attention combine to create an environment of serene, understated luxury.', 'https://www.pangkorlautresort.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(659, 'Hard Rock Hotel Penang', 'Hard Rock', 'Hard Rock International', 'Penang', '', 'We believe that true luxury lies in the moments that take your breath away. Our purpose is to craft a seamless narrative for your stay, where every experience, from a private dinner to a quiet morning coffee, is thoughtfully designed to become an unforgettable memory.', 'https://www.hardrockhotels.com/penang/', '', '2025-08-29 15:20:37', 'Malaysia'),
(660, 'Eastern & Oriental Hotel', 'E&O', 'Eastern & Oriental Berhad', 'Penang', '', 'Your stay is a carefully composed symphony of sophisticated design and warm, intuitive hospitality. The stunning visual aesthetics of our spaces are perfectly matched by a service culture that anticipates your needs, ensuring a stay that is as flawless as it is beautiful.', 'https://www.eohotels.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(661, 'Traders Hotel Kuala Lumpur', 'Traders', 'Shangri-La Hotels and Resorts', 'Kuala Lumpur', '', 'Discover a true haven of serenity nestled in the heart of the vibrant city. Our property is a destination in itself, offering a peaceful respite where you can unwind in an atmosphere of bespoke luxury and escape the ordinary in every possible way.', 'https://www.shangri-la.com/kualalumpur/traders/', '', '2025-08-29 15:20:37', 'Malaysia'),
(662, 'InterContinental Kuala Lumpur', 'InterContinental', 'IHG Hotels & Resorts', 'Kuala Lumpur', '', 'Welcome to the pinnacle of opulence, an establishment dedicated to providing a truly transcendent guest experience. We go beyond mere accommodation to offer a lifestyle of glamour, comfort, and exclusivity that will redefine your expectations of what a hotel can be.', 'https://www.ihg.com/intercontinental/hotels/us/en/kuala-lumpur/kulha/hoteldetail', '', '2025-08-29 15:20:37', 'Malaysia'),
(663, 'Sofitel Kuala Lumpur Damansara', 'Sofitel', 'Accor', 'Kuala Lumpur', '', 'From the moment you arrive, you will step into a realm of exceptional style and uncompromising quality. Every element of our hotel has been chosen with intent, reflecting a commitment to superior craftsmanship, aesthetic integrity, and the highest standards of guest comfort.', 'https://www.sofitel-kualalumpur-damansara.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(664, 'Rebak Island Resort & Marina, Langkawi', 'Taj', 'Indian Hotels Company Ltd. (IHCL)', 'Langkawi', '', 'We don\'t just offer a place to stay; we curate a comprehensive and immersive experience tailored to your desires. Our goal is for you to depart with a unique story to tell, filled with moments of discovery, relaxation, and unparalleled personal service.', 'https://www.rebakislandresort.com/', '', '2025-08-29 15:20:37', 'Malaysia'),
(665, 'AVANI Sepang Goldcoast Resort', 'Avani', 'Minor Hotels', 'Sepang', '', 'As a landmark of distinguished hospitality, our hotel is an icon of architectural grace and refined living. We honor our legacy by continuing a tradition of excellence, offering a timeless escape for those who appreciate history, elegance, and world-class service.', 'https://www.minorhotels.com/en/avani/sepang', '', '2025-08-29 15:20:37', 'Malaysia'),
(666, 'Banyan Tree Bangkok', 'Banyan Tree', 'Banyan Group', 'Bangkok', '', 'Experience hospitality gracefully redefined, where our service philosophy is built on quiet anticipation. Our team is expertly trained to foresee your needs and fulfill them with a seamless elegance that ensures your stay is utterly effortless and perfectly choreographed.', 'https://www.banyantree.com/thailand/bangkok', '', '2025-08-29 15:20:37', 'Thailand'),
