(732, 'Vinpearl Landmark 81, Autograph Collection', 'Autograph Collection', 'Marriott International', 'Ho Chi Minh City', '', 'An environment of bespoke luxury and artisanal craftsmanship awaits you at every turn. From hand-stitched leather accents to custom-forged metalwork, our commitment to quality is tangible, offering a feast for the eyes and a testament to fine design.', 'https://www.marriott.com/en-us/hotels/sgnva-vinpearl-landmark-81-autograph-collection/overview/', '', '2025-08-29 15:20:37', 'Vietnam'),
(733, 'Caravelle Saigon', 'Caravelle Saigon', 'Independent', 'Ho Chi Minh City', '', 'Indulge in unparalleled comfort with our signature plush furnishings, intuitive state-of-the-art amenities, and serene soundproofing. Every room is an enclave designed for deep relaxation and a perfect night\'s sleep, ensuring you wake up refreshed and inspired.', 'https://www.caravellehotel.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(734, 'Rex Hotel Saigon', 'Rex Hotel', 'Saigon Tourist Holding Company', 'Ho Chi Minh City', '', 'Within our walls, aesthetic beauty and ultimate comfort exist in perfect, harmonious balance. The visual delight of our interiors is matched only by the physical comfort of our accommodations, ensuring a stay that satisfies both the eye and the soul.', 'https://www.rexhotelvietnam.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(735, 'Hotel Des Arts Saigon, MGallery', 'MGallery', 'Accor', 'Ho Chi Minh City', '', 'For those seeking the pinnacle of refinement, our suites offer an elevated experience of space, privacy, and exquisite detail. Featuring separate living areas, expansive views, and exclusive amenities, they represent the ultimate expression of our luxurious hospitality.', 'https://www.hoteldesartssaigon.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(736, 'Four Seasons Resort The Nam Hai, Hoi An', 'Four Seasons', 'Four Seasons Hotels and Resorts', 'Hoi An', '', 'Prepare to embark on an epicurean journey that tantalizes the senses and expands the palate. Our dining venues are celebrated destinations, each offering a unique culinary story told through innovative menus and the freshest seasonal ingredients.', 'https://www.fourseasons.com/hoian/', '', '2025-08-29 15:20:37', 'Vietnam'),
(737, 'Anantara Hoi An Resort', 'Anantara', 'Minor Hotels', 'Hoi An', '', 'We invite you to savor gastronomic excellence at our world-class dining destinations. Helmed by acclaimed chefs, our restaurants are temples of culinary creativity, where every dish is a work of art and every meal is an unforgettable event.', 'https://www.anantara.com/en/hoi-an', '', '2025-08-29 15:20:37', 'Vietnam'),
(738, 'Banyan Tree Lang Co', 'Banyan Tree', 'Banyan Group', 'Thua Thien Hue', '', 'Rejuvenate your mind, body, and soul in our tranquil and exclusive wellness sanctuary. Offering a curated menu of restorative treatments, cutting-edge fitness equipment, and serene relaxation areas, it is a space wholly dedicated to your personal wellbeing.', 'https://www.banyantree.com/vietnam/lang-co', '', '2025-08-29 15:20:37', 'Vietnam'),
(739, 'The Imperial Hue', 'The Imperial Hue', 'Independent', 'Hue', '', 'Our hotel is a celebrated destination for both culinary artistry and masterful mixology. Gather in our stylish bar for a handcrafted cocktail before transitioning to a dinner that showcases global flavors and exquisite culinary technique.', 'https://www.imperial-hotel.com.vn/', '', '2025-08-29 15:20:37', 'Vietnam'),
(740, 'Fusion Resort Cam Ranh', 'Fusion', 'Lodgis Hospitality Holdings Pte. Ltd.', 'Cam Ranh', '', 'Escape to a state of blissful relaxation with our bespoke spa treatments and holistic wellness programs. Our expert therapists use world-class products and personalized techniques to melt away stress, leaving you feeling balanced, restored, and radiant.', 'https://www.fusionresorts.com/fusionresortcamranh', '', '2025-08-29 15:20:37', 'Vietnam'),
(741, 'InterContinental Da Nang Sun Peninsula Resort', 'InterContinental', 'IHG Hotels & Resorts', 'Da Nang', '', 'Indulge in vibrant and authentic culinary creations crafted from the finest locally-sourced and seasonal ingredients. Our food philosophy is rooted in a passion for quality and sustainability, bringing you a true taste of the region\'s best offerings.', 'https://www.danang.intercontinental.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(742, 'Premier Village Da Nang Resort', 'Premier', 'Accor', 'Da Nang', '', 'Discover a holistic approach to wellbeing that extends beyond our spa to encompass every aspect of your stay. From nourishing menu options to in-room wellness amenities, we provide the tools to help you maintain balance and vitality while you travel.', 'https://www.premier-village-danang.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(743, 'Hyatt Regency Danang Resort and Spa', 'Hyatt Regency', 'Hyatt Hotels', 'Da Nang', '', 'From the casual elegance of our all-day bistro to the refined ambiance of our signature fine dining room, a taste of perfection awaits. We offer a diverse array of culinary settings, each defined by its exceptional quality and impeccable service.', 'https://www.hyatt.com/en-US/hotel/vietnam/hyatt-regency-danang-resort-and-spa/danhr', '', '2025-08-29 15:20:37', 'Vietnam'),
(744, 'Pullman Da Nang Beach Resort', 'Pullman', 'Accor', 'Da Nang', '', 'Your personal journey to tranquility and rejuvenation begins the moment you enter our wellness space. It is a quiet, restorative world designed to soothe the senses, calm the mind, and provide a peaceful escape from the demands of daily life.', 'https://www.pullman-danang.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(745, 'The Ritz-Carlton, Hanoi', 'The Ritz-Carlton', 'Marriott International', 'Hanoi', '', 'Join us for a celebration of flavor, artistry, and exceptional service in our acclaimed restaurants. We create dining experiences that are both sophisticated and deeply satisfying, making every meal a special and memorable occasion.', 'https://www.ritzcarlton.com/en/hotels/hanrz-the-ritz-carlton-hanoi', '', '2025-08-29 15:20:37', 'Vietnam');
INSERT INTO `hotels` (`id`, `hotel_name`, `parent_company`, `sub_brand`, `city`, `state`, `description`, `website_url`, `hero_image_url`, `created_at`, `country`) VALUES
(746, 'Six Senses Con Dao', 'Six Senses', 'IHG Hotels & Resorts', 'Con Dao Island', '', 'We offer more than just amenities; we provide the definitive experience of modern luxury. This is a place where sophisticated design, intuitive technology, and a forward-thinking approach to hospitality converge to create an environment that is as inspiring as it is comfortable.', 'https://www.sixsenses.com/en/resorts/con-dao', '', '2025-08-29 15:20:37', 'Vietnam'),
(747, 'JW Marriott Phu Quoc Emerald Bay Resort & Spa', 'JW Marriott', 'Marriott International', 'Phu Quoc Island', '', 'To stay with us is to inhabit an address of distinction and international prestige. Our iconic property is more than a hotel—it is a landmark of culture and sophistication, offering an exclusive and elegant base from which to experience the world.', 'https://www.marriott.com/en-us/hotels/pqcjw-jw-marriott-phu-quoc-emerald-bay-resort-and-spa/overview/', '', '2025-08-29 15:20:37', 'Vietnam'),
(748, 'La Veranda Resort Phu Quoc', 'MGallery', 'Accor', 'Phu Quoc Island', '', 'We have built our reputation on the belief that extraordinary experiences should be the standard, not the exception. Every aspect of our operation, from our grand public spaces to the smallest in-room detail, is engineered to exceed expectations and deliver delight.', 'https://www.laverandaresorts.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(749, 'InterContinental Phu Quoc Long Beach Resort', 'InterContinental', 'IHG Hotels & Resorts', 'Phu Quoc Island', '', 'Consider us your private and luxurious escape from the everyday. We provide a protected, elegant environment where the pressures of the world fade away, allowing you the time and space to reconnect with yourself and savor the quiet moments of peace and comfort.', 'https://www.phuquoc.intercontinental.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(750, 'Vinpearl Resort & Spa Ha Long', 'Vinpearl', 'Vinpearl', 'Ha Long Bay', '', 'Welcome to the ultimate expression of refined living, where every detail has been considered for a life lived beautifully. Our hotel is for those who appreciate the finer things—art, design, gastronomy, and service—all delivered with an effortless, confident grace.', 'https://www.vinpearl.com/en/hotels/vinpearl-resort-and-spa-ha-long', '', '2025-08-29 15:20:37', 'Vietnam'),
(751, 'Meliá Vinpearl Ha Long Bay', 'Meliá', 'Meliá Hotels International', 'Ha Long Bay', '', 'Our experience has been meticulously curated for those who expect the very best and appreciate a discerning eye for quality. We are not for everyone; we are for the traveler who seeks a unique, character-rich environment that stands apart from the ordinary.', 'https://www.melia.com/en/hotels/vietnam/ha-long/melia-vinpearl-ha-long-bay', '', '2025-08-29 15:20:37', 'Vietnam'),
(752, 'Dalat Palace Heritage Hotel', 'Dalat Palace', 'DL Royal Joint Stock Company', 'Da Lat', '', 'Here, timeless elegance and unforgettable moments are woven into the very fabric of the guest experience. We offer a classic, enduring style of luxury, focusing on creating genuine, heartfelt memories that you will cherish long after you have departed.', 'https://www.dalatpalacehotel.com/', '', '2025-08-29 15:20:37', 'Vietnam'),
(753, 'An Lam Retreats Ninh Van Bay', 'An Lam Retreats', 'An Lam Retreats', 'Ninh Van Bay', '', 'We are proud to set a new standard in bespoke hospitality, moving beyond a one-size-fits-all approach to luxury. We listen, we learn, and we adapt, creating a highly personalized and fluid experience that is built entirely around you, the individual guest.', 'https://www.anlam.com/ninh-van-bay/our-retreat/', '', '2025-08-29 15:20:37', 'Vietnam'),
(754, 'Azerai Can Tho', 'Azerai', 'Azerai Resorts', 'Can Tho', '', 'Discover the art of luxury, perfectly expressed in every facet of our hotel. It is an art form that we have perfected over years, balancing grandeur with intimacy, and tradition with innovation, to create a masterpiece of modern hospitality.', 'https://www.azerai.com/resorts/azerai-can-tho', '', '2025-08-29 15:20:37', 'Vietnam'),
(755, 'Amanoi', 'Aman', 'Aman Resorts', 'Ninh Thuan Province', '', 'Welcome to a world beyond compare, where the boundaries of service and luxury are constantly being reimagined. Your stay with us is an invitation to experience the extraordinary and to see just how magnificent and memorable travel can truly be.', 'https://www.aman.com/resorts/amanoi', '', '2025-08-29 15:20:37', 'Vietnam'),
(756, 'Jaypee Residency Manor', 'Jaypee Group', 'Manor', 'Mussoorie', 'Uttarakhand', NULL, 'https://www.jaypeehotels.com/hotel/jaypee-residency-manor-mussoorie', '/hotel-images/jaypee-residency-manor.jpg', '2025-09-13 10:10:55', NULL),
